from __future__ import annotations
import json, shutil
from pathlib import Path
from typing import Any
from .account_readonly_config import AccountReadonlyConfig, build_account_readonly_config
from .account_readonly_provider import AccountReadonlyProvider
from .account_rate_limit import AccountReadonlyRateLimiter
from .account_masking import mask_account_id, mask_account_name

REQ=["local_console_xttrader_stage90/xttrader_boundary_config.json","local_console_xttrader_stage90/xttrader_import_guard_report.json","local_console_xttrader_stage90/xttrader_capability_probe.json","local_console_xttrader_stage90/xttrader_account_query_gate.json","local_console_xttrader_stage90/xttrader_order_submit_gate.json","local_console_xttrader_stage90/order_previews.json","local_console_xttrader_stage90/xttrader_safety_report.json","local_console_xttrader_stage90/xttrader_boundary_report.json","local_console_xttrader_stage90/frontend_xttrader_contract.json"]
FORBIDDEN=["order_"+"stock","order_"+"stock_"+"async","cancel_order_"+"stock","cancel_order_"+"stock_"+"async","place_"+"order","execute_"+"order","real_order_submitted="+"true","allow_order_submit="+"true","allow_order_cancel="+"true"]

def _dump(o): return json.dumps(o,ensure_ascii=False,indent=2,sort_keys=True)
def _write(base,stem,obj):
    base.mkdir(parents=True,exist_ok=True); (base/f"{stem}.json").write_text(_dump(obj)+"\n",encoding="utf-8"); (base/f"{stem}.md").write_text(f"# {stem}\n\n```json\n{_dump(obj)}\n```\n",encoding="utf-8")
def _read(p:Path):
    try: return json.loads(p.read_text(encoding='utf-8')) if p.exists() else None
    except Exception: return None

def build_config(repo_root='.', enable=False, allow_import=False, allow_connect=False, allow_account=False, allow_position=False, manual=False, dry_run=True, read_only=True):
    params={'enable_account_readonly': str(bool(enable)).lower(), 'allow_import_xttrader': str(bool(allow_import)).lower(), 'allow_connect_trade_session': str(bool(allow_connect)).lower(), 'allow_account_query': str(bool(allow_account)).lower(), 'allow_position_query': str(bool(allow_position)).lower(), 'manual_confirmed': str(bool(manual)).lower(), 'dry_run': str(bool(dry_run)).lower(), 'read_only': str(bool(read_only)).lower()}
    return build_account_readonly_config(repo_root, params)

def scan_stage91_safety(repo_root='.'):
    root=Path(repo_root); files=list((root/'qmt_ai_trading/trading_gateway').glob('account_*.py'))+list((root/'scripts').glob('*stage91*.py'))
    hits=[]
    for f in files:
        txt=f.read_text(encoding='utf-8',errors='ignore').lower().replace(' ','')
        for m in FORBIDDEN:
            if m in txt: hits.append({'file':str(f.relative_to(root)),'marker':m})
    return {'status':'PASS' if not hits else 'FAIL','hits':hits,'read_only':True,'order_submit_enabled':False,'order_cancel_enabled':False,'real_order_submitted':False,'no_order_submitted':True,'no_order_cancelled':True,'safety_status':'DISABLED_FOR_SAFETY'}

def build_frontend(repo_root:Path):
    app=repo_root/'local_console_app_stage91'; app.mkdir(parents=True,exist_ok=True)
    html = '<!doctype html>\n<html lang="zh-CN">\n<head>\n  <meta charset="utf-8">\n  <title>账户只读 / 持仓只读</title>\n  <style>\n    body{font-family:Arial,\'Microsoft YaHei\',sans-serif;margin:24px;background:#f8fafc;color:#172033}.card{background:white;border-radius:12px;padding:16px;margin:12px 0;box-shadow:0 1px 6px #d7dce5}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:12px}.badge{display:inline-block;padding:6px 10px;border-radius:99px;background:#e0f2fe;color:#075985}.warn{color:#b45309}.ok{color:#047857}button{margin:4px;padding:8px 12px;border-radius:8px;border:1px solid #cbd5e1;background:#f8fafc;cursor:pointer}table{width:100%;border-collapse:collapse}th,td{border-bottom:1px solid #e5e7eb;text-align:left;padding:8px}pre{background:#0f172a;color:#e5e7eb;padding:12px;border-radius:8px;white-space:pre-wrap}label{display:block;line-height:1.6}</style>\n</head>\n<body>\n<h1>账户只读 / 持仓只读</h1>\n<nav>账户只读 · 持仓只读</nav>\n<div class="grid">\n  <div class="card" id="accountStatus">账户查询：默认关闭</div><div class="card" id="positionStatus">持仓查询：默认关闭</div><div class="card">真实下单：关闭</div><div class="card">撤单能力：关闭</div><div class="card">账号脱敏：开启</div><div class="card">限频保护：开启</div>\n</div>\n<p><span class="badge" id="safetyBadge">MANUAL_CONFIRM_REQUIRED</span></p>\n<section class="card">\n  <h2>人工确认区</h2>\n  <label><input id="manualConfirm" type="checkbox"> 我确认本次只进行账户/持仓只读查询；不下单、不撤单、不自动交易；查询结果仅用于风险校验和灰度准备。</label>\n  <p id="message" class="warn"></p>\n  <button id="enableReadonly">启用账户/持仓只读查询</button><button id="disableReadonly">关闭账户只读模式</button><button id="refreshAsset">刷新资产</button><button id="refreshPositions">刷新持仓</button>\n</section>\n<section class="card"><h2>账户资产摘要</h2><div id="asset"><p>账户状态：默认关闭</p></div></section>\n<section class="card"><h2>持仓列表</h2><div id="pos"><p>持仓查询：默认关闭</p></div></section>\n<section class="card"><h2>查询频率状态</h2><div id="rate">每分钟最多 3 次<br>当前剩余次数：--</div></section>\n<section class="card"><h2>账号脱敏状态</h2><div>账号脱敏：已开启<br>完整账号不会写入日志和前端</div></section>\n<section class="card"><h2>查询模式</h2><p>查询模式：隔离子进程，只读，查询后自动释放连接</p></section>\n<section class="card"><h2>安全边界</h2><pre>read_only=true\norder_submit_enabled=false\norder_cancel_enabled=false\nreal_order_submitted=false\naccount_masked=true</pre></section>\n<details class="card"><summary>原始 JSON 折叠区</summary><pre id="raw"></pre></details>\n<script>\nconst accountReadonlyState = { enabled: false, manualConfirmed: false, symbols: [], lastStatus: null, lastAsset: null, lastPositions: null };\nconst enabledParams = {enable_account_readonly:\'true\',allow_import_xttrader:\'true\',allow_connect_trade_session:\'true\',allow_account_query:\'true\',allow_position_query:\'true\',manual_confirmed:\'true\',read_only:\'true\',dry_run:\'true\',allow_order_submit:\'false\',allow_order_cancel:\'false\'};\nfunction qs(){ return accountReadonlyState.enabled ? \'?\' + new URLSearchParams(enabledParams).toString() : \'\'; }\nasync function j(path){ const r = await fetch(path + qs()); return r.json(); }\nfunction money(v){ return \'¥\' + Number(v || 0).toLocaleString(\'zh-CN\',{minimumFractionDigits:2,maximumFractionDigits:2}); }\nfunction setMsg(t, cls=\'warn\'){ message.textContent=t; message.className=cls; }\nfunction renderStatus(s){ accountStatus.textContent=\'账户查询：\' + (s.account_query_enabled?\'只读查询已启用\':\'默认关闭\'); positionStatus.textContent=\'持仓查询：\' + (s.position_query_enabled?\'只读查询已启用\':\'默认关闭\'); safetyBadge.textContent=s.safety_status||s.status||\'DISABLED\'; if(s.ok===false){ setMsg(s.error_message||s.message||\'只读查询失败\'); } }\nfunction renderAsset(a){ if(a.ok===false){ asset.innerHTML=`<p>账户状态：查询失败</p><p class="warn">${a.error_message||a.message||a.status}</p>`; setMsg(a.error_message||\'资产只读查询失败\'); return; } const x=a.asset||{}; asset.innerHTML=`<p>账户状态：${a.account_query_enabled||accountReadonlyState.enabled?\'只读查询已启用\':\'默认关闭\'}</p><p>账号：${x.account_id_masked||x.account_id||\'--\'}</p><p>总资产：${money(x.total_asset)}</p><p>可用资金：${money(x.available_cash??x.cash)}</p><p>持仓市值：${money(x.market_value)}</p><p>数据来源：${a.mock_data?\'Mock fallback\':\'MiniQMT 只读查询\'}</p>`; }\nfunction renderPositions(p){ if(p.ok===false){ pos.innerHTML=`<p>持仓查询：查询失败</p><p class="warn">${p.error_message||p.message||p.status}</p>`; setMsg(p.error_message||\'持仓只读查询失败\'); return; } const box=p.positions||{}; const rows=Array.isArray(box)?box:(box.positions||[]); pos.innerHTML=\'<table><thead><tr><th>证券代码</th><th>证券名称</th><th>持仓数量</th><th>可用数量</th><th>成本价</th><th>最新价</th><th>持仓市值</th><th>浮动盈亏</th><th>只读状态</th></tr></thead><tbody>\'+rows.map(x=>`<tr><td>${x.symbol||\'\'}</td><td>${x.name||\'\'}</td><td>${x.volume||0}</td><td>${x.available_volume||0}</td><td>${x.cost_price||0}</td><td>${x.latest_price||0}</td><td>${x.market_value||0}</td><td>${x.floating_pnl||0}</td><td>${x.read_only?\'只读\':\'只读\'}</td></tr>`).join(\'\')+\'</tbody></table>\'; }\nfunction renderRaw(){ raw.textContent=JSON.stringify({status:accountReadonlyState.lastStatus,asset:accountReadonlyState.lastAsset,positions:accountReadonlyState.lastPositions},null,2); }\nasync function refreshStatus(){ const s=await j(\'/api/v1/account-readonly/status\'); accountReadonlyState.lastStatus=s; renderStatus(s); renderRaw(); return s; }\nasync function refreshAssetOnly(){ const a=await j(\'/api/v1/account-readonly/asset\'); accountReadonlyState.lastAsset=a; renderAsset(a); renderRaw(); }\nasync function refreshPositionsOnly(){ const p=await j(\'/api/v1/account-readonly/positions\'); accountReadonlyState.lastPositions=p; renderPositions(p); renderRaw(); }\nasync function refreshAllReadonly(){ setMsg(\'正在启动隔离只读查询进程，请稍等，最多 30 秒...\',\'ok\'); const r=await fetch(\'/api/v1/account-readonly/refresh\' + qs(), {method:\'POST\'}); let data={ok:false,status:\'FAILED\'}; try{ data=await r.json(); }catch(e){ data={ok:false,status:\'FAILED\',error_message:String(e)}; } if(r.status===403){ setMsg(\'接口被本地 API 白名单拦截：请检查 refresh 是否加入白名单。\'); accountReadonlyState.lastAsset=data; accountReadonlyState.lastPositions=data; renderRaw(); return data; } accountReadonlyState.lastAsset=data; accountReadonlyState.lastPositions=data; if(data.status===\'SUBPROCESS_TIMEOUT\'){ setMsg(\'只读查询超时，已自动终止。\'); renderAsset(data); renderPositions(data); renderRaw(); return data; } renderAsset(data); renderPositions(data); if(data.ok){ setMsg(\'账户/持仓只读查询成功；查询模式：隔离子进程，只读，查询后释放连接\',\'ok\'); } else { setMsg(data.error_message||\'子进程只读查询失败\'); } renderRaw(); return data; }\nenableReadonly.onclick=async()=>{ if(!manualConfirm.checked){ setMsg(\'请先勾选人工确认。\'); return; } accountReadonlyState.enabled=true; accountReadonlyState.manualConfirmed=true; setMsg(\'正在启动隔离只读查询进程，请稍等，最多 30 秒...\',\'ok\'); await refreshAllReadonly(); };\ndisableReadonly.onclick=async()=>{ accountReadonlyState.enabled=false; accountReadonlyState.manualConfirmed=false; manualConfirm.checked=false; setMsg(\'账户只读模式已关闭。\'); await refreshStatus(); };\nrefreshAsset.onclick=refreshAssetOnly; refreshPositions.onclick=refreshPositionsOnly;\nPromise.all([refreshStatus(),refreshAssetOnly(),refreshPositionsOnly(),j(\'/api/v1/account-readonly/rate-limit\')]).then(([, , , r])=>{rate.innerHTML=`每分钟最多 ${r.max_queries_per_minute||3} 次<br>当前剩余次数：${r.remaining ?? \'--\'}`});\n</script>\n</body>\n</html>\n'
    (app/'index.html').write_text(html,encoding='utf-8')

def run_account_readonly_stage91(repo_root='.', output_dir='local_console_account_stage91', enable_account_readonly=False, allow_import_xttrader=False, allow_connect_trade_session=False, allow_account_query=False, allow_position_query=False, manual_confirmed=False, dry_run=True, read_only=True):
    root=Path(repo_root); out=root/output_dir; canon=root/'artifacts/reports/stage91/account_readonly'
    inputs={p:{'exists':(root/p).exists(),'data':_read(root/p)} for p in REQ}; fallback=any(not v['exists'] for v in inputs.values())
    cfg=build_config(root, enable_account_readonly,allow_import_xttrader,allow_connect_trade_session,allow_account_query,allow_position_query,manual_confirmed,dry_run,read_only)
    provider=AccountReadonlyProvider(cfg, rate_limiter=AccountReadonlyRateLimiter(cfg.max_queries_per_minute))
    context={'stage':'Stage91','input_files':{k:{'exists':v['exists']} for k,v in inputs.items()},'fallback_used':fallback,'mock_data':True,'account_readonly_boundary':True,'account_query_enabled':False,'position_query_enabled':False,'order_submit_enabled':False,'real_order_submitted':False,'dry_run':True,'read_only':True,'requires_human_approval':True,'mask_account_required':True}
    status=provider.get_status(); diagnostics=provider.diagnostics(); asset=provider.query_account_asset(); positions=provider.query_positions()
    masking={'status':'PASS','account_masked':True,'sample_account_id':mask_account_id('1234567890'),'sample_account_name':mask_account_name('示例账户名称'),'full_account_absent':True,'mask_account_required':True}
    rl=AccountReadonlyRateLimiter(3); rate={'attempts':[rl.allow(),rl.allow(),rl.allow(),rl.allow()],'rate_limit_required':True,'max_queries_per_minute':3}
    safety=scan_stage91_safety(root)
    frontend={'menu':['账户只读','持仓只读'],'endpoints':['/api/v1/account-readonly/status','/api/v1/account-readonly/diagnostics','/api/v1/account-readonly/asset','/api/v1/account-readonly/positions','/api/v1/account-readonly/masking-report','/api/v1/account-readonly/rate-limit','/api/v1/account-readonly/safety','/api/v1/account-readonly/report'],'manual_confirmation_text':'我确认本次只进行账户/持仓只读查询；不下单、不自动交易；查询结果仅用于风险校验和灰度准备。','forbidden_actions_absent':True,**status}
    plan={'stage':'Stage92','title':'真实订单预览复核，不发单','uses_account_readonly':True,'order_submit_enabled':False,'real_order_submitted':False,'requires_human_approval':True}
    report={'stage':'Stage91','status':'SUCCESS' if safety['status']=='PASS' else 'FAIL','output_dir':str(out),'canonical_dir':str(canon),'account_readonly_status':status,'account_readonly_diagnostics':diagnostics,'position_count':positions.get('position_count',0),'workflow_status':{'QMT Gateway / xtdata':'INTERACTIVE','Data Hub':'INTERACTIVE','Research':'INTERACTIVE','Strategy':'INTERACTIVE','Risk Gate':'INTERACTIVE','Paper Trading':'INTERACTIVE','xttrader Boundary':'DISABLED_FOR_SAFETY','Account Readonly':'MANUAL_CONFIRM_REQUIRED','Order Submit':'DISABLED_FOR_SAFETY'},**status,'order_submit_enabled':False,'real_order_submitted':False,'no_order_submitted':True}
    docs={'account_input_context':context,'account_readonly_config':cfg.to_dict(),'account_readonly_status':status,'account_readonly_diagnostics':diagnostics,'account_asset_snapshot':asset,'account_positions_snapshot':positions,'account_masking_report':masking,'account_rate_limit_report':rate,'account_readonly_safety_report':safety,'account_readonly_report':report,'frontend_account_contract':frontend,'next_order_preview_review_plan':plan}
    for base in (out,canon):
        for k,o in docs.items(): _write(base,k,o)
    build_frontend(root); return report
